const { CosmosClient } = require("@azure/cosmos");
const { AppInsights } = require("applicationinsights");
const { Context } = require("@azure/functions");

const endpoint = process.env.COSMOS_DB_ENDPOINT;
const key = process.env.COSMOS_DB_KEY;
const databaseId = process.env.DATABASE_ID;
const containerId = process.env.CONTAINER_ID;

const client = new CosmosClient({ endpoint, key });
const database = client.database(databaseId);
const container = database.container(containerId);

module.exports = async function (context, req) {
    context.res = { status: 200 };

    // Set function timeout to maximum (10 minutes)
    context.executionContext.setTimeout(600000);

    // Validate input
    const inputData = req.body;
    if (!inputData || !Array.isArray(inputData)) {
        context.res = { status: 400, body: "Invalid input data" };
        return;
    }

    try {
        // Process data in batches
        const batchSize = 100; // Adjust batch size as necessary
        for (let i = 0; i < inputData.length; i += batchSize) {
            const batch = inputData.slice(i, i + batchSize);
            await processBatch(batch);
        }
        context.res.body = "Batch processing completed successfully.";
    } catch (error) {
        context.log.error("Error processing batches: ", error);
        context.res = { status: 500, body: "Internal server error" };
    }
};

async function processBatch(batch) {
    const operations = batch.map(item => {
        // Validate each item in the batch
        if (!item.id || !item.data) {
            throw new Error("Invalid item in batch");
        }
        return container.items.upsert(item);
    });
    await Promise.all(operations);
}